import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def calculate_distance(p1, p2):
        return np.linalg.norm(p1 - p2)

    def time_to_node(start_pos, end_pos, speed):
        distance = calculate_distance(start_pos, end_pos)
        return distance / speed

    best_node = None
    min_time_cost = float('inf')
    urgency_factor_adjustment = np.random.uniform(0.9, 1.1)  # Random factor to modify urgency slightly

    # Calculate cluster centers for unvisited customers
    num_clusters = min(len(unvisited_customers), 3)  # Maximum of 3 clusters
    if len(unvisited_customers) > 1:
        from sklearn.cluster import KMeans
        kmeans = KMeans(n_clusters=num_clusters)
        kmeans.fit(unvisited_customers)
        cluster_centers = kmeans.cluster_centers_
    else:
        cluster_centers = unvisited_customers  # If only one customer, it is the center

    for i, customer in enumerate(unvisited_customers):
        travel_time = time_to_node(cur_truck_pos, customer, truck_speed)
        arrival_time = current_time + travel_time
        window_open, window_close = time_windows[i]

        if arrival_time > window_close:
            penalty_time = (arrival_time - window_close)**2
        elif arrival_time < window_open:
            penalty_time = (window_open - arrival_time) + truck_speed * 0.1  # Penalty with slight advantage to waiting
        else:
            penalty_time = 0  # No penalty for perfect timing

        # Finding the nearest cluster center to current customer to prioritize dense areas
        nearest_cluster_distance = min(calculate_distance(customer, center) for center in cluster_centers)
        urgency = (window_close - arrival_time) * urgency_factor_adjustment  # Adjusted closer to zero implies higher urgency

        time_cost = (arrival_time + penalty_time) / (1.0 + np.exp(-urgency / 30)) + nearest_cluster_distance / 5  # Using softmax-like component for urgency

        if time_cost < min_time_cost:
            min_time_cost = time_cost
            best_node = i

    if best_node is None:
        return None  # Instruct the truck to wait if no optimal node is found
    return best_node
